-- Уроки главы "Управляющие конструкции" (chapter_id = 1)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Конструкция if-else в Go', 'Знакомство с условным ветвлением в Go.',
                                                                           'Оператор if в Go проверяет логическое условие и выполняет блок кода только в случае, если это условие истинно. В отличие от многих других языков, Go не требует круглых скобок вокруг условия, однако открывающая фигурная скобка обязательно должна находиться на той же строке, что и условие. За оператором if может следовать одна или несколько ветвей else if, а также необязательная финальная ветвь else, которая выполняется, если ни одно из предыдущих условий не оказалось истинным. Go также позволяет добавить перед условием короткую инициализацию, отделённую точкой с запятой — это часто используется для объявления переменной, область видимости которой ограничена только блоком if-else, что предотвращает утечку вспомогательных переменных в окружающую область видимости функции.',
                                                                           1, 1),
                                                                          ('Конструкция switch в Go', 'Использование switch как более чистой альтернативы длинным цепочкам if-else.',
                                                                           'Оператор switch в Go позволяет сравнить значение со списком возможных вариантов, не прибегая к длинной цепочке операторов if-else. В отличие от некоторых других языков, Go автоматически прерывает выполнение после сработавшей ветки case, поэтому для продолжения выполнения в следующую ветку нужно явно указать ключевое слово fallthrough. Оператор switch также может использоваться без выражения — в этом случае каждая ветка case содержит собственное логическое условие, что делает его читаемой альтернативой длинной цепочке if-else. Switch может работать со многими типами данных, включая целые числа, строки и даже сами типы через конструкцию type switch.',
                                                                           2, 1);

-- Уроки главы "Типы данных и переменные" (chapter_id = 2)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Базовые типы данных в Go', 'Обзор встроенных примитивных типов Go.',
                                                                           'Go — статически типизированный язык, то есть тип каждой переменной известен уже на этапе компиляции. В языке есть несколько категорий встроенных типов: числовые типы, такие как int, float64 и их варианты фиксированного размера вроде int32 и int64; тип bool для значений true/false; и тип string для представления текста как неизменяемой последовательности байт. Go также предоставляет составные типы, построенные на основе этих примитивов, такие как массивы, срезы (slices) и словари (maps), которые рассматриваются в следующих главах. Выбор подходящего числового типа влияет как на потребление памяти, так и на диапазон значений, которые может хранить переменная.',
                                                                           1, 2),
                                                                          ('Переменные и константы', 'Объявление и инициализация переменных и констант в Go.',
                                                                           'Переменные в Go можно объявлять явно с помощью ключевого слова var, указав имя и тип, либо неявно с помощью оператора короткого объявления, при котором тип определяется автоматически по присваиваемому значению. Go требует, чтобы каждая объявленная переменная была где-то использована в коде, иначе компилятор выдаст ошибку. Константы объявляются с помощью ключевого слова const и должны получать значение, известное уже на этапе компиляции, например числовой литерал или строку. В отличие от переменных, константы нельзя переприсвоить после объявления, что делает их удобными для значений, которые должны оставаться неизменными на протяжении всей программы — например, для лимитов конфигурации или математических констант.',
                                                                           2, 2);

-- Уроки главы "Введение в Python" (chapter_id = 3)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Основы синтаксиса Python', 'Базовые правила синтаксиса, определяющие структуру кода Python.',
                                                                           'Python использует отступы вместо фигурных скобок для обозначения блоков кода, поэтому последовательное форматирование отступов — это не просто стилистическое предпочтение, а требование синтаксиса. Типичная программа на Python состоит из инструкций, выполняемых последовательно сверху вниз, при этом управляющие конструкции, такие как условные операторы и циклы, вводят блоки с отступом. Python — динамически типизированный язык, поэтому переменной не требуется явное объявление типа: её тип определяется присвоенным значением во время выполнения программы. Комментарии в Python записываются с помощью символа решётки, а многострочные строки в тройных кавычках часто используются для более объёмных блоков документации.',
                                                                           1, 3),
                                                                          ('Работа со списками и словарями', 'Две наиболее часто используемые встроенные структуры данных в Python.',
                                                                           'Список (list) в Python — это упорядоченная изменяемая коллекция, которая может хранить элементы разных типов, при этом элементы можно добавлять, удалять или изменять после создания списка. Списки поддерживают индексацию и срезы, что позволяет обращаться к отдельным элементам или диапазону элементов с помощью квадратных скобок. Словарь (dictionary) хранит данные в виде пар ключ-значение, обеспечивая быстрый поиск значения по связанному с ним ключу, а не по числовой позиции. Обе структуры поддерживают перебор элементов с помощью цикла for, а словари дополнительно позволяют перебирать ключи, значения или пары ключ-значение вместе.',
                                                                           2, 3);

-- Уроки главы "Функции и модули" (chapter_id = 4)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Объявление функций в Python', 'Как писать и вызывать переиспользуемые блоки кода.',
                                                                           'Функция в Python объявляется с помощью ключевого слова def, за которым следует имя, список параметров в круглых скобках и двоеточие, открывающее блок кода с отступом. Функции могут принимать значения параметров по умолчанию, которые используются, если вызывающий код явно не передал этот аргумент. Оператор return используется для возврата значения вызывающему коду; если в функции нет явного оператора return, она неявно возвращает специальное значение None. Python также поддерживает списки аргументов переменной длины с помощью синтаксиса со звёздочкой, что позволяет функции принимать произвольное количество позиционных или именованных аргументов.',
                                                                           1, 4),
                                                                          ('Импорт и использование модулей', 'Организация и переиспользование кода в нескольких файлах.',
                                                                           'Модуль в Python — это файл с кодом на Python, который можно импортировать и переиспользовать в других файлах с помощью инструкции import. Python включает обширную стандартную библиотеку встроенных модулей, охватывающих такие задачи, как работа с файлами, математические вычисления и работа с датой и временем. Конкретную функцию или объект можно импортировать напрямую из модуля с помощью синтаксиса from-import, что избавляет от необходимости каждый раз указывать полное имя модуля. Организация связанных функций и классов в отдельные модули, а модулей — в пакеты, помогает поддерживать читаемость крупных проектов по мере их роста.',
                                                                           2, 4);

-- Уроки главы "Основы JavaScript" (chapter_id = 5)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Переменные и типы данных в JavaScript', 'Объявление переменных и основные типы данных JavaScript.',
                                                                           'В JavaScript есть три ключевых слова для объявления переменных: var, let и const. Ключевые слова let и const были введены, чтобы решить проблемы с областью видимости, присущие var, ограничивая видимость переменной блоком, в котором она объявлена, а не всей функцией целиком. JavaScript — динамически типизированный язык и включает примитивные типы number, string, boolean, undefined и null, а также тип object для более сложных структур. Ключевое слово const объявляет переменную, которую нельзя переприсвоить после начальной инициализации, хотя объекты и массивы, объявленные через const, всё ещё можно изменять изнутри.',
                                                                           1, 5),
                                                                          ('Функции и область видимости', 'Как объявляются функции и как область видимости определяет доступность переменных.',
                                                                           'Функции в JavaScript можно объявлять несколькими способами: как объявление функции, как функциональное выражение, присвоенное переменной, либо как стрелочная функция с укороченным синтаксисом. Стрелочные функции отличаются от обычных тем, как они обрабатывают ключевое слово this — они наследуют его из окружающего контекста, а не определяют собственное. Область видимости в JavaScript определяет, какие части кода могут обращаться к той или иной переменной: блочная область видимости применяется к переменным, объявленным через let и const, а функциональная область видимости — к переменным, объявленным через var. Замыкания (closures) возникают, когда функция сохраняет доступ к переменным из содержащей её области видимости даже после завершения работы внешней функции.',
                                                                           2, 5);

-- Уроки главы "Работа с DOM" (chapter_id = 6)
INSERT INTO lessons (name, description, content, "order", chapter_id) VALUES
                                                                          ('Выбор и изменение элементов DOM', 'Чтение и изменение содержимого страницы с помощью JavaScript.',
                                                                           'Document Object Model, или DOM, представляет HTML-страницу в виде дерева узлов, которое JavaScript может читать и изменять. Элементы можно выбирать с помощью методов getElementById, querySelector и querySelectorAll, которые возвращают одну или несколько ссылок на подходящие элементы страницы. После того как элемент выбран, его содержимое можно изменить через свойства textContent или innerHTML, а внешний вид — через изменение списка классов или отдельных стилевых свойств. Поскольку изменения DOM напрямую влияют на то, что видит пользователь, чрезмерные или частые изменения могут снизить производительность страницы, поэтому часто рекомендуется группировать обновления.',
                                                                           1, 6),
                                                                          ('Обработка событий в JavaScript', 'Реакция на действия пользователя, такие как клики и ввод с клавиатуры.',
                                                                           'Обработка событий позволяет JavaScript реагировать на действия пользователя, такие как нажатие кнопки, отправка формы или нажатие клавиши. Метод addEventListener привязывает функцию к элементу, которая выполняется при каждом наступлении указанного события, причём к одному элементу можно привязать несколько обработчиков без взаимного перезаписывания. Объект события, передаваемый обработчику, содержит детали взаимодействия — например, какая клавиша была нажата или какой элемент вызвал событие. Всплытие событий определяет порядок, в котором вложенные элементы получают событие: сначала оно движется от самого внешнего предка вниз к целевому элементу на фазе перехвата, а затем обратно вверх на фазе всплытия.',
                                                                           2, 6);

